{
  "app": {
    "name": "Oh My Coder",
    "one_sentence": "A Chinese-focused, open-source multi-agent AI coding assistant supporting 12+ domestic LLMs with full offline operation and zero-cost usage.",
    "inspired_by": "oh-my-claudecode"
  },
  "core_loop": "User issues natural language coding tasks via CLI or web interface; the system routes requests to specialized agents within a 31-agent ecosystem, leveraging layered memory and asynchronous Quest Mode for autonomous programming, while ensuring all processing remains local and private.",
  "screens": [
    {
      "id": "main",
      "name": "Main Interface",
      "purpose": "Provide entry point for user to input coding tasks and view agent responses in Chinese.",
      "primary_actions": [
        "Submit coding task",
        "View agent response",
        "Access settings"
      ]
    },
    {
      "id": "settings",
      "name": "Model Configuration",
      "purpose": "Allow user to configure API keys and select among 12+ supported Chinese LLMs.",
      "primary_actions": [
        "Set GLM_API_KEY",
        "Set DEEPSEEK_API_KEY",
        "Switch active model"
      ]
    }
  ],
  "rust_commands": [
    {
      "name": "omc_run",
      "purpose": "Execute a natural language coding command using the configured LLM and agent system.",
      "async": true,
      "input": {
        "command": "string"
      },
      "output": {
        "result": "string"
      }
    },
    {
      "name": "omc_config_set",
      "purpose": "Set configuration parameters such as API keys for supported models.",
      "async": false,
      "input": {
        "key": "string",
        "value": "string"
      },
      "output": {
        "status": "string"
      }
    }
  ],
  "data_model": {
    "tables": [
      {
        "name": "agents",
        "fields": [
          {
            "name": "id",
            "type": "string"
          },
          {
            "name": "name_zh",
            "type": "string"
          },

